async function safeFetch(url) {
  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`HTTP Error ${response.status}: ${response.statusText}`);
  }

  return response.json();
}

async function main() {
  // Valid request:
  try {
    const user = await safeFetch("https://jsonplaceholder.typicode.com/users/1");
    console.log("Got user:", user.name);
  } catch (e) {
    console.log("Error:", e.message);
  }

  // 404 request:
  try {
    const notFound = await safeFetch("https://jsonplaceholder.typicode.com/users/9999");
  } catch (e) {
    console.log("Not found error:", e.message);
  }
}

main();

async function createPost(data) {
  const response = await fetch("https://jsonplaceholder.typicode.com/posts", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json();
}

async function main() {
  const newPost = await createPost({
    title: "My First Post",
    body: "Hello from JavaScript!",
    userId: 1,
  });
  console.log("Created:", newPost.id);
  console.log("Title:", newPost.title);
}

main();

