async function fetchPosts(filters) {
  const params = new URLSearchParams(filters);
  const url = `https://jsonplaceholder.typicode.com/posts?${params}`;
  console.log("URL:", url);

  const response = await fetch(url);
  const posts = await response.json();
  return posts;
}

async function main() {
  const posts = await fetchPosts({ userId: 1 });
  console.log("Posts count:", posts.length);
  console.log("First post:", posts[0].title);
}

main();

instruction:
APIs often require authentication via headers:

```js
fetch(url, {
  headers: {
    'Authorization': 'Bearer your-token',
    'Accept': 'application/json',
  }
})
```

Build a reusable `apiClient` that always adds auth headers.

starter:
function createApiClient(baseUrl, token) {
  const defaultHeaders = {
    "Content-Type": "application/json",
    "Accept": "application/json",
    ...(token && { "Authorization": `Bearer ${token}` }),
  };

  return {
    async get(path) {
      const r = await fetch(`${baseUrl}${path}`, { headers: defaultHeaders });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    },
    async post(path, data) {
      const r = await fetch(`${baseUrl}${path}`, {
        method: "POST",
        headers: defaultHeaders,
        body: JSON.stringify(data),
      });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    }
  };
}

const api = createApiClient("https://jsonplaceholder.typicode.com", "fake-token");

async function main() {
  const user = await api.get("/users/1");
  console.log("User:", user.name);
}
main();

function fetchWithTimeout(url, ms = 5000) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), ms);

  return fetch(url, { signal: controller.signal })
    .then(r => {
      clearTimeout(timeoutId);
      return r.json();
    })
    .catch(e => {
      if (e.name === 'AbortError') throw new Error(`Timeout after ${ms}ms`);
      throw e;
    });
}

async function main() {
  try {
    const data = await fetchWithTimeout("https://jsonplaceholder.typicode.com/users/1", 5000);
    console.log("Got:", data.name);
  } catch(e) {
    console.log("Error:", e.message);
  }
}
main();

async function loadUserWithPosts(userId) {
  const [user, posts] = await Promise.all([
    fetch(`https://jsonplaceholder.typicode.com/users/${userId}`).then(r => r.json()),
    fetch(`https://jsonplaceholder.typicode.com/posts?userId=${userId}`).then(r => r.json()),
  ]);

  return { ...user, posts };
}

async function main() {
  const user = await loadUserWithPosts(1);
  console.log("User:", user.name);
  console.log("Posts:", user.posts.length);
  console.log("First post:", user.posts[0].title);
}
main();
